$datos = array(
    "ver" => 1,
    "fecha" => $fecha_factura_qr,
    "cuit" => $cuit_emisor_qr,
    "ptoVta" => $pto_vta_qr,
    "tipoCmp" => $tipoCmp_qr,
    "nroCmp" => $nroCmp_qr,
    "importe" => $importe_qr,
    "moneda" => $moneda,
    "ctz" => $ctz_qr,
    "tipoDocRec" => $tipoDocRec_qr,
    "nroDocRec" => $nroDocRec_qr,
    "tipoCodAut" => "E",
    "codAut" => intval($cae)
);

$json_resultado = json_encode($datos, JSON_NUMERIC_CHECK);
$base64_resultado = base64_encode($json_resultado);
$cadena = "https://www.arca.gob.ar/fe/qr/?p=$base64_resultado";

$options = new QROptions([
    'version' => QRCode::VERSION_AUTO,
    'outputType' => QRCode::OUTPUT_IMAGE_PNG,
    'eccLevel' => QRCode::ECC_L,
    'scale' => 5,
    'imageBase64'  => false,
    'moduleValues' => [],
]);

$qrcode = new QRCode($options);
$imageData = $qrcode->render($cadena);
$carpetaQR = "../images/qr/$id/";

if (!file_exists($carpetaQR)) {
    mkdir($carpetaQR, 0777, true);
}

$archivoQR = "$carpetaQR$id.png";
file_put_contents($archivoQR, $imageData);

